return await ((ctx, host) => {
  const last = ctx.transcript.at(-1);
  if (last && last.role === "assistant" && last.content.trim().length < 40) {
    host.log("terse reply flagged");
    return { kind: "note", text: "That reply looked brief \u2014 want more detail?" };
  }
  return { kind: "none" };
})(ctx, host);
